// src/components/rawMaterials/RawMaterialList.jsx
import React, { useEffect, useState } from 'react';
import { getAllRawMaterials, deleteRawMaterial } from '../../api/rawMaterialApi';
import RawMaterialForm from './RawMaterialForm';

const RawMaterialList = () => {
  const [materials, setMaterials] = useState([]);
  const [editingMaterial, setEditingMaterial] = useState(null);

  const fetchMaterials = async () => {
    try {
      const response = await getAllRawMaterials();
      setMaterials(response.data);
    } catch (error) {
      console.error('Error fetching raw materials:', error);
    }
  };

  useEffect(() => {
    fetchMaterials();
  }, []);

  const handleDelete = async (id) => {
    try {
      await deleteRawMaterial(id);
      fetchMaterials();
    } catch (error) {
      console.error('Error deleting raw material:', error);
    }
  };

  return (
    <div>
      <RawMaterialForm
        material={editingMaterial}
        onSuccess={() => {
          setEditingMaterial(null);
          fetchMaterials();
        }}
      />
      <ul>
        {materials.map((m) => (
          <li key={m.id}>
            {m.name} - Quantity: {m.quantity}
            <button onClick={() => setEditingMaterial(m)}>Edit</button>
            <button onClick={() => handleDelete(m.id)}>Delete</button>
          </li>
        ))}
      </ul>
    </div>
  );
};

export default RawMaterialList;
